// The Metric Catalog: the single registry of every Metric the dataset can rank or chart, and the
// stability contract for the comparison dataset — entries change only by deliberate schema revision,
// so historical Runs stay comparable. A parsed result whose id isn't here is inert: it's reported
// separately for visibility, never ranked, until someone adds a matching entry.
//
// The PTS-backed Metrics are GENERATED from the vendored upstream `test-definition.xml` profiles
// (pts-generated.ts, regenerated by `generate-catalog` and held byte-stable by the drift gate), then
// curated at import time by the hand-authored override map (pts-overrides.ts) — the merge below. The
// generator owns the XML-derived fields (id/unit/direction/pts) and id-uniqueness; the override supplies
// the editorial fields the XML can't (a short `label`, the one `headline:true` per dimension, any
// `dimension` correction). The previously hand-authored cpu entry (node-web-tooling) is now this
// generated module's wildcard entry; its curation lives in pts-overrides.ts.
import { economicsMetrics } from "./economics.ts";
import { harnessMetrics } from "./harness-metrics.ts";
import type { Dimension, MetricDef } from "./metrics.ts";
import { metricDefSchema } from "./metrics.ts";
import { ptsGenerated } from "./pts-generated.ts";
import { ptsOverrides } from "./pts-overrides.ts";

// The generated draft refined by curation, keyed by id (`{ ...generated, ...override }`): the override
// wins only on the fields it declares (label/headline/dimension), the generator owns the rest.
//
// Both wired suites' synthesized `pts.description` strings are proven to byte-match real PTS output by
// the golden gate (packages/results pts-golden.test): node-web-tooling (wildcard) and the c-ray
// option matrix, the latter against a recorded c-ray-2.0.0 composite (design §3.7). A drift would turn
// that gate red rather than silently routing results to `uncatalogued`.
const ptsCurated: MetricDef[] = ptsGenerated.map((def) => ({ ...def, ...ptsOverrides[def.id] }));

// Fail fast if a curation key matches no generated id — e.g. a profile regen renamed a slug. The merge
// iterates generated ids and never the override keys, so an orphaned key would otherwise no-op silently
// and the verbose generated label would ship. The drift gate guards the generated file against rot; this
// guards the hand-authored overrides against the same.
const generatedIds = new Set(ptsGenerated.map((def) => def.id));
const orphanedOverrides = Object.keys(ptsOverrides).filter((id) => !generatedIds.has(id));
if (orphanedOverrides.length > 0) {
	throw new Error(
		`pts-overrides.ts targets unknown metric id(s): ${orphanedOverrides.sort().join(", ")}`,
	);
}

/**
 * The Catalog schema: every entry's shape PLUS the PTS-mapping invariant the runtime relies on. The
 * `.narrow` makes the dangerous catalog shape UNCONSTRUCTABLE so `ptsResultToMetric`'s wildcard
 * fallback (pts.ts) is safe by construction rather than by reviewer vigilance — for any one PTS test:
 *   1. at most one description-less wildcard entry,
 *   2. a wildcard never coexists with description-bearing entries, and
 *   3. entries sharing a `<Description>` are disambiguated by DISTINCT `pts.scale` pins on every one
 *      of them (fio: the same run posts a bandwidth and an IOPS `<Result>` under one description) —
 *      never a scale-less twin the description-first matcher would resolve arbitrarily.
 * Any of these would let a `<Result>` be misattributed (fall to the wrong twin or the wildcard);
 * forbidding the shape at load (deterministic, CI-caught) removes that path.
 * Exported so the invariant is unit-testable against crafted catalogs, independent of the singleton.
 */
export const catalogSchema = metricDefSchema.array().narrow((cat, ctx) => {
	const wildcardTests = new Set<string>();
	const describedTests = new Set<string>();
	// (test, description) -> the pts.scale pins seen for that description (undefined = no pin).
	const scalesByDescription = new Map<string, (string | undefined)[]>();
	for (const metric of cat) {
		if (!metric.pts) continue;
		if (metric.pts.description === undefined) {
			if (wildcardTests.has(metric.pts.test)) {
				return ctx.mustBe(
					`at most one description-less wildcard per PTS test ("${metric.pts.test}")`,
				);
			}
			wildcardTests.add(metric.pts.test);
		} else {
			describedTests.add(metric.pts.test);
			const key = JSON.stringify([metric.pts.test, metric.pts.description]);
			const scales = scalesByDescription.get(key) ?? [];
			scales.push(metric.pts.scale);
			scalesByDescription.set(key, scales);
		}
	}
	for (const test of wildcardTests) {
		if (describedTests.has(test)) {
			return ctx.mustBe(
				`no description-bearing entries alongside the description-less wildcard for "${test}"`,
			);
		}
	}
	for (const [key, scales] of scalesByDescription) {
		if (scales.length < 2) continue;
		// Every twin must carry a pin, and no two pins may repeat — stated directly so there is no
		// cross-array length arithmetic to repair wrongly.
		if (scales.includes(undefined) || new Set(scales).size !== scales.length) {
			return ctx.mustBe(
				`entries sharing a description disambiguated by distinct pts.scale pins on all of them (${key})`,
			);
		}
	}
	return true;
});

/**
 * The full Catalog, validated at load. Dimensions land in display order as their Metrics are ported;
 * the runtime `.assert` turns a malformed entry (bad dimension/direction, missing field) — or a
 * violated PTS-mapping invariant ({@link catalogSchema}) — into a fail-fast at import rather than a
 * silently broken stability contract.
 *
 * The PTS-derived slice (generated + curated) is followed by the hand-authored harness-measured
 * Metrics (lifecycle + control-plane) and the derived economics Metrics; neither carries a `pts` field,
 * so the PTS-mapping invariant skips them while id-uniqueness and the one-headline-per-dimension check
 * below still cover them.
 */
export const METRIC_CATALOG: readonly MetricDef[] = catalogSchema.assert([
	...ptsCurated,
	...harnessMetrics,
	...economicsMetrics,
]);

const byId = new Map(METRIC_CATALOG.map((metric) => [metric.id, metric]));

// Two Metrics sharing an id would silently collapse in `byId` (and corrupt getMetric); fail fast at
// import — the schema validates each entry's shape but not id-uniqueness across the registry.
if (byId.size !== METRIC_CATALOG.length) {
	throw new Error("METRIC_CATALOG contains duplicate metric ids");
}

// Exactly one headline per dimension is an editorial invariant the override map controls; catalogSchema
// validates entry shape and the wildcard rules but NOT this. A second `headline:true` (a one-line slip in
// pts-overrides.ts) would otherwise pass load and let `headlineMetric` silently return whichever entry
// catalog order happens to hit first. Fail fast instead.
const headlineDimensions = new Set<Dimension>();
for (const metric of METRIC_CATALOG) {
	if (!metric.headline) continue;
	if (headlineDimensions.has(metric.dimension)) {
		throw new Error(
			`dimension "${metric.dimension}" has multiple headline metrics — exactly one is allowed`,
		);
	}
	headlineDimensions.add(metric.dimension);
}

/** Look up a Metric by id; undefined for ids not in the Catalog. */
export function getMetric(id: string): MetricDef | undefined {
	return byId.get(id);
}

/** Every Metric belonging to a Dimension, in Catalog order. */
export function metricsForDimension(dimension: Dimension): MetricDef[] {
	return METRIC_CATALOG.filter((metric) => metric.dimension === dimension);
}

/** The first headline Metric of a Dimension — what the leaderboard shows. Throws if none exists. */
export function headlineMetric(dimension: Dimension): MetricDef {
	const headline = METRIC_CATALOG.find(
		(metric) => metric.dimension === dimension && metric.headline,
	);
	if (!headline) throw new Error(`Dimension ${dimension} has no headline Metric`);
	return headline;
}
